SELECT COUNT(*) AS qtd_servidores FROM SERVIDOR S WHERE LOWER(S.AREA_INGRESSO) = LOWER('historia') AND LOWER(S.SIGLA_CAMPUS) = LOWER('apa') AND LOWER(S.CONTRATO) = LOWER('efetivos') AND S.SAIU_DO_IFG = FALSE AND (S.DATA_INGRESSO_IFG IS NOT NULL AND S.DATA_INGRESSO_IFG <= '2020-06-30') AND (S.DATA_NASCIMENTO IS NULL OR S.DATA_NASCIMENTO <= '2020-06-30')